#include <iostream>
using namespace std;

class Shape {
public:
 virtual void area() = 0; // Pure virtual function
 virtual ~Shape() {} // Virtual destructor
};

class Circle : public Shape {
 float radius;
public:
 Circle(float r) : radius(r) {}
 void area() override {
 cout << "Circle Area: " << 3.14 * radius * radius << endl;
 }
};

class Rectangle : public Shape {
 float length, breadth;
public:
 Rectangle(float l, float b) : length(l), breadth(b) {}
 void area() override {
 cout << "Rectangle Area: " << length * breadth << endl;
 }
};

int main() {
 Shape* ptr; // Base class pointer
 Circle c(5);
 Rectangle r(4, 6);

 ptr = &c;
 ptr->area(); // Calls Circle::area()

 ptr = &r;
 ptr->area(); // Calls Rectangle::area()

 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 Base() { cout << "Base Constructor\n"; }
 virtual ~Base() { cout << "Base Destructor\n"; }
};

class Derived : public Base {
public:
 Derived() { cout << "Derived Constructor\n"; }
 ~Derived() { cout << "Derived Destructor\n"; }
};

int main() {
 Base* ptr = new Derived();
 delete ptr; // Calls both destructors due to virtual
 return 0;
}

// Output:
// Base Constructor
// Derived Constructor
// Derived Destructor
// Base Destructor

#include <iostream>
using namespace std;

class Base {
public:
 virtual void show() const {
 cout << "Base show()\n";
 }
 virtual void display() final {
 cout << "Base display() - cannot override\n";
 }
};

class Derived : public Base {
public:
 void show() override { // Explicit override
 cout << "Derived show()\n";
 }
 // void display() override {} // Error! display() is final
};

int main() {
 Base* ptr = new Derived();
 ptr->show(); // Calls Derived::show()
 ptr->display(); // Calls Base::display()
 return 0;
}

#include <iostream>
#include <string>
using namespace std;

class Animal {
protected:
 string name;
public:
 Animal(string n) : name(n) {}
 virtual void speak() = 0; // Pure virtual function
 virtual ~Animal() {}
};

class Dog : public Animal {
public:
 Dog(string n) : Animal(n) {}
 void speak() override {
 cout << name << " says: Woof!\n";
 }
};

class Cat : public Animal {
public:
 Cat(string n) : Animal(n) {}
 void speak() override {
 cout << name << " says: Meow!\n";
 }
};

int main() {
 // Animal a; // Error! Cannot instantiate abstract class
 Animal* animals[2];
 animals[0] = new Dog("Buddy");
 animals[1] = new Cat("Whiskers");

 for(int i = 0; i < 2; i++)
 animals[i]->speak();

 return 0;
}
